 wire sel; 
 assign sel = sel_akiko && address_in[7:1]==8'b0011_100; 
 always @(posedge clk) 
  if (reset) 
  wrpointer <= 0; 
  else if (!rd && sel) 
  begin 
  case(wrpointer) 
  0 : shifter[127:112] <= data_in[15:0]; 
