 input reset ; 
 input enable ; 
 input init ; 
 input [7:0] data_in ; 
 output [15:0] crc_out; 
 reg [15:0] crc_reg; 
 wire [15:0] next_crc; 
 assign crc_out = crc_reg; 
 always @ (posedge clk) 
 if (reset) begin 
  crc_reg <= 16'hFFFF; 
 end else if (enable) begin 
  if (init) begin 
  crc_reg <= 16'hFFFF; 
