module rtlpp_11725 (
  input   wire    CLK,
  input   wire    RESETn,
  output  wire    By2CLK,
  output  wire    By4CLK,
  output  wire    By8CLK,
  output  wire    By16CLK,
  output  wire    By32CLK
);

  reg [4:0]   counter;

  reg         by2clk_r;
  reg         by4clk_r;
  reg         by8clk_r;
  reg         by16clk_r;
  reg         by32clk_r;

  always @(posedge CLK or negedge RESETn) begin
    if(~RESETn)
      counter <= 5'h0;
    else 
      counter <= counter + 1'b1;
  end

  always @(posedge CLK or negedge RESETn) begin
