module autovcoder_001841 (
    A,
    B,
    Ci,
    S,
    Co
);
  input [3:0] A, B;
  input Ci;
  output [3:0] S;
  output Co;
  wire [3:0] A, B, S;
  wire Ci, Co;
  wire [2:0] C;

  adder1bit u1 (
      A[0],
      B[0],
      Ci,
      S[0],
      C[0]
  );
  adder1bit u2 (
      A[1],
      B[1],
