module origen_212729 #(
    parameter ADDR_WIDTH = 9,
    parameter DATA_WIDTH = 8
)(
    // Port A
    input  wire                 clock_a,
    input  wire                 enable_a,
    input  wire                 wren_a,
    input  wire [ADDR_WIDTH-1:0] address_a,
    input  wire [DATA_WIDTH-1:0] data_a,
    output reg  [DATA_WIDTH-1:0] q_a,
    output reg  [DATA_WIDTH-1:0] rdata_a,

    // Port B
    input  wire                 clock_b,
    input  wire                 enable_b,
    input  wire                 wren_b,
    input  wire [ADDR_WIDTH-1:0] address_b,
    input  wire [DATA_WIDTH-1:0] data_b,
    output reg  [DATA_WIDTH-1:0] q_b,
    output reg  [DATA_WIDTH-1:0] rdata_b
);

    // Internal RAM
    reg [DATA_WIDTH-1:0] ram [0:(1<<ADDR_WIDTH)-1];

    // Port A
    always @(posedge clock_a) begin
        if (enable_a) begin
            if (wren_a) begin
                ram[address_a] <= data_a;
            end
            q_a <= ram[address_a];
        end
    end

    always @(posedge clock_a) begin
        rdata_a <= q_a;
    end

    // Port B
    always @(posedge clock_b) begin
        if (enable_b) begin
            if (wren_b) begin
                ram[address_b] <= data_b;
            end
            q_b <= ram[address_b];
        end
    end

    always @(posedge clock_b) begin
        rdata_b <= q_b;
    end

endmodule

