module origen_056999 #(
    parameter N_BLOCKS = 16383,
    parameter EXTRA_DELAY = 0
) (
    input wire i_clock,
    input wire i_reset,
    input wire i_enable,
    input wire i_valid,
    input wire i_restart,
    output reg o_start_of_lane
);

    localparam COUNTER_WIDTH = $clog2(N_BLOCKS);

    reg [COUNTER_WIDTH-1:0] counter;
    reg state;

    localparam INIT = 1'b0;
    localparam LOCKED = 1'b1;

    always @(posedge i_clock or posedge i_reset or posedge i_restart) begin
        if (i_reset || i_restart) begin
            counter <= 0;
            state <= INIT;
            o_start_of_lane <= 1'b0;
        end else if (i_enable && i_valid) begin
            case (state)
                INIT: begin
                    if (counter == N_BLOCKS - EXTRA_DELAY - 1) begin
                        counter <= 0;
                        state <= LOCKED;
                        o_start_of_lane <= 1'b1;
                    end else begin
                        counter <= counter + 1;
                        o_start_of_lane <= 1'b0;
                    end
                end

                LOCKED: begin
                    if (counter == N_BLOCKS - 1) begin
                        counter <= 0;
                        o_start_of_lane <= 1'b1;
                    end else begin
                        counter <= counter + 1;
                        o_start_of_lane <= 1'b0;
                    end
                end
            endcase
        end else begin
            o_start_of_lane <= 1'b0;
        end
    end

endmodule

