  5'h14: seg_reg = 8'b1010_0011; 
  5'h15: seg_reg = 8'b1010_1011; 
  5'h16: seg_reg = 8'b1000_0110; 
  default:seg_reg = 8'b1111_1111; 
  endcase 
 assign out_dig = dig_ctrl; 
