module rtlpp_11149(clk, nrst, rx_data, rx_busy, rx_done, rx_err, rxd);

parameter CLK_HZ = 200_000_000;
parameter BAUD = 9600;
parameter BAUD_DIVISOR_2 = CLK_HZ / BAUD / 2;

input wire clk;
input wire nrst;

output reg [7:0] rx_data = 0;
reg rx_data_9th_bit = 0;	

output reg rx_busy = 0;
output wire rx_done;		
output wire rx_err;
input wire rxd;

reg [1:0] shift_reg = 2'b0;
reg s_rxd;

always @ (posedge clk or negedge nrst) begin
	if (~nrst) begin
		shift_reg <= 2'b0;
		s_rxd <= 1'b0;
	end else begin
		shift_reg <= {shift_reg[0], rxd};
		s_rxd <= shift_reg[1];
	end
end

reg rxd_prev = 0;
always @ (posedge clk or negedge nrst) begin
	if (~nrst) begin
		rxd_prev <= 0;
	end else begin
		rxd_prev <= s_rxd;
	end
end
wire start_bit_strobe = ~s_rxd & rxd_prev;

reg [15:0] rx_sample_cntr = (BAUD_DIVISOR_2 - 1);
wire rx_do_sample = (rx_sample_cntr[15:0] == 0);

always @ (posedge clk or negedge nrst) begin
	if (~nrst) begin
		rx_busy <= 0;
		rx_sample_cntr <= (BAUD_DIVISOR_2 - 1);
		rx_data <= 8'b0;
		rx_data_9th_bit <= 0;
	end else begin
		if (~rx_busy) begin
			if (start_bit_strobe) begin
				rx_sample_cntr <= (BAUD_DIVISOR_2 * 3 - 1);		
				{rx_data, rx_data_9th_bit} <= 9'b100000000;
				rx_busy <= 1;
			end
		end else begin
			if (rx_sample_cntr == 0) begin
				rx_sample_cntr <= (BAUD_DIVISOR_2 * 2 - 1);
			end else begin
				rx_sample_cntr <= rx_sample_cntr - 1;
			end

			if (rx_do_sample) begin
				if (rx_data_9th_bit == 1) begin
					rx_busy <= 0;
				end else begin
					{rx_data, rx_data_9th_bit} <= {s_rxd, rx_data};
				end
			end 
		end	
	end 
end

assign rx_done = rx_data_9th_bit && rx_do_sample && s_rxd;		
assign rx_err = rx_data_9th_bit && rx_do_sample && ~s_rxd;

endmodule

