module mg_09911 (input clk,input rst,input miso,output mosi,output sck,input start,input[7:0] data_in,output[7:0] data_out,output busy,output new_data);
localparam CLK_DIV=3; 
 localparam IDLE = 3'd0, 
  TRANSFER = 3'd1; 
 reg [2:0] state; 
 reg [7:0] data; 
 reg [CLK_DIV-1:0] sck_q; 
 assign sck = (sck_q[CLK_DIV-1] && state!=IDLE); 
 reg mosi; 
 reg [2:0] ctr; 
 reg [7:0] data_out; 
 reg new_data; 
 reg busy; 
 always @(posedge clk) begin 
  if (!rst) begin 
  ctr <= 3'b0; 
  sck_q <= 3'h0; 
  mosi <= 1'b0; 
  state <= IDLE; 
  data_out <= 8'b0; 
  new_data <= 1'b0; 
  end else begin 
  case (state) 
  IDLE: begin 
  sck_q <= 3'h0; 
  ctr <= 3'b0; 
  if (start == 1'b1) begin 
  busy<=1'b1; 
  new_data <= 1'b0; 
  data <= data_in; 
  state <= TRANSFER; 
  end 
  end 
  TRANSFER: begin 
  sck_q <= sck_q + 1'b1; 
  case(sck_q) 
  3'b000: begin 
  end 
  3'b001: begin 
  end 
  3'b010: begin 
  mosi <= data[7]; 
  end 
  3'b011: begin 
  end 
  3'b100: begin 
  end 
  3'b101: begin 
  end 
  3'b110: begin 
  data <= {data[6:0], miso}; 
  end 
  3'b111: begin 
  ctr <= ctr + 1'b1; 
  if (ctr == 3'b111) begin 
