module rtlpp_10633(
    clk,
    rd_n,
    wr_n,
    cs_n,
    a,
    reset,
    d,
    pb,
    pc,
    pa
);

input clk;
input rd_n, wr_n, cs_n;
input [1:0] a;
input reset;
inout [7:0] d;
input [7:0] pa, pc;
output [7:0] pb;

reg [7:0] pb, pdo;
reg [7:0] pdi;
reg [1:0] flag;

wire pds;
wire [4:0] cmd;
wire rst_n;

assign d = (pds == 1'b1) ? pdo : 8'bzzzzzzzz;
assign cmd = {a[1], a[0], rd_n, wr_n, cs_n};
assign pds = ((cmd == 5'b00010) | (cmd == 5'b10010) | (cmd == 5'b01010));
assign rst_n = ~reset;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        flag <= 2'b00;
        pdi <= 8'b11111111;
    end
    else if (cs_n == 1'b1) begin
        flag <= 2'b00;
        pdi <= pdi;
    end
    else if (flag == 2'b00) begin
        flag <= 2'b01;
        pdi <= pdi;
    end
    else if (flag == 2'b01) begin
        flag <= 2'b10;
        pdi <= d;
    end
    else if (flag == 2'b10) begin
        flag <= 2'b11;
        pdi <= pdi;
    end
    else begin
        flag <= flag;
        pdi <= pdi;
    end
end

always @(cmd or reset) begin
    if (reset == 1'b1) begin
        pdo <= 8'b0;
    end
    else if (cmd == 5'b00010) begin
        pdo <= pa;
    end
    else if (cmd == 5'b10010) begin
        pdo <= pc;
    end
    else if (cmd == 5'b01010) begin
        pdo <= pb;
    end
    else begin
        pdo <= pdo;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
        pb <= 8'b11111111;
    end
    else if (cmd == 5'b01100) begin
        pb <= d;
    end
    else begin
        pb <= pb;
    end
end

endmodule

