        rst_dqs_div_out_reg <= rst_dqs_div_in;
    end

    // Internal signals for data path
    reg [1:0] ddr_dm_reg;
    reg [1:0] dqs_int_delay_in_reg;
    reg [15:0] dq_reg;

    assign ddr_dm = ddr_dm_reg;
    assign dqs_int_delay_in = dqs_int_delay_in_reg;
    assign dq = dq_reg;

    always @(posedge clk90) begin
        if (dqs_reset) begin
            ddr_dm_reg <= 2'b0;
            dqs_int_delay_in_reg <= 2'b0;
            dq_reg <= 16'b0;
        end else if (dqs_enable && write_en_val) begin
            dq_reg <= write_data_rising;
        end else if (dqs_enable && !write_en_val) begin
            dq_reg <= write_data_falling;
        end
        ddr_dm_reg <= {data_mask_r, data_mask_f};
    end

endmodule

