module autovcoder_100609 (
    clka,
    adra,
    dia,
    doa,
    cea,
    wea,
    rsta,
    clkb,
    adrb,
    dib,
    dob,
    ceb,
    web,
    rstb
);
  parameter pAw = 10;
  parameter pDw = 16;
  input clka;
  input [pAw:1] adra;
  input [pDw:1] dia;
  output [pDw:1] doa;
  input cea;  // clock enable a
  input wea;
  input rsta;
  input clkb;
  input [pAw:1] adrb;
  input [pDw:1] dib;
  output [pDw:1] dob;
  input ceb;  // clock enable b
  input web;
  input rstb;

`ifdef VENDOR_XILINX

`ifdef SPARTAN3
  // could use an S16_S32
  RAMB16_S18_S18 ram0 (
      .CLKA (clka),
      .ADDRA(adra),
      .DIA  (dia),
      .DIPA (2'b11),
      .DOA  (doa),
      .ENA  (cea),
      .WEA  (wea),
      .SSRA (rsta),
      .CLKB (clkb),
      .ADDRB(adrb),
      .DIB  (dib),
      .DIPB (2'b11),
      .DOB  (dob),
      .ENB  (ceb),
      .WEB  (web),
      .SSRB (rstb)
  );
`else
  // could use an S8_S16
  RAMB4_S8_S8 ram0 (
      .CLKA (clka),
      .ADDRA(adra),
      .DIA  (dia),
      .DOA  (doa),
      .ENA  (cea),
      .WEA  (wea),
      .RSTA (rsta),
      .CLKB (clkb),
      .ADDRB(adrb),
      .DIB  (dib),
      .DOB  (dob),
      .ENB  (ceb),
      .WEB  (web),
      .RSTB (rstb)
  );
`endif
`endif

`ifdef VENDOR_ALTERA
`endif

`ifdef VENDOR_ANY

  reg [15:0] mem[(1<<pAw):1];
  reg [pAw:1] radra;
  reg [pAw:1] radrb;

  // register read addresses
  always @(posedge clka) if (cea) radra <= adra;

  always @(posedge clkb) if (ceb) if (web) mem[adrb] <= dib;

  assign doa = mem[radra];

`endif

endmodule

