module autovcoder_088750 (
    Input_1,
    Input_10,
    Input_11,
    Input_12,
    Input_2,
    Input_3,
    Input_4,
    Input_5,
    Input_6,
    Input_7,
    Input_8,
    Input_9,
    Result
);

  /***************************************************************************
    ** Here all module parameters are defined with a dummy value             **
    ***************************************************************************/
  parameter BubblesMask = 1;


  /***************************************************************************
    ** Here the inputs are defined                                           **
    ***************************************************************************/
  input Input_1;
  input Input_10;
  input Input_11;
  input Input_12;
  input Input_2;
  input Input_3;
  input Input_4;
  input Input_5;
  input Input_6;
  input Input_7;
  input Input_8;
  input Input_9;

  /***************************************************************************
    ** Here the outputs are defined                                          **
    ***************************************************************************/
  output Result;

  /***************************************************************************
