module counter706(CE, 
                  CLK, 
                  CLR, 
                  CEO, 
                  Q0, 
                  Q1, 
                  Q2, 
                  TC);

    input CE;
    input CLK;
    input CLR;

    output Q0;
    output Q1;
    output Q2;
    output TC;
    output CEO;

    reg Q0_DUMMY = 1'b1;
    reg Q1_DUMMY = 1'b1;
    reg Q2_DUMMY = 1'b1;
    reg Q3 = 1'b1;

    wire XLXN_1 = 1'b1;
    wire XLXN_2 = 1'b1;
    wire XLXN_8;
    wire XLXN_3;
    wire XLXN_4;
    wire XLXN_5;
