    wire XLXN_22;
    wire XLXN_23;

    assign Q0 = Q0_DUMMY;
    assign Q1 = Q1_DUMMY;
    assign Q2 = Q2_DUMMY;

    always @(posedge CLK or posedge CLR) begin
        if (CLR) begin
            Q0_DUMMY <= 1'b1;
        end else if (CE) begin
            Q0_DUMMY <= ~Q0_DUMMY;
        end
    end

    assign XLXN_4 = Q0_DUMMY & Q3;
    assign XLXN_7 = ~Q3;
    assign XLXN_6 = ~Q0_DUMMY;
    assign XLXN_5 = XLXN_6 & XLXN_7;
    assign XLXN_3 = XLXN_4 | XLXN_5;

    always @(posedge CLK or posedge CLR) begin
        if (CLR) begin
            Q1_DUMMY <= 1'b1;
        end else if (CE) begin
            if (XLXN_2 == 1) begin
                if (XLXN_3 == 0) begin
                    Q1_DUMMY <= 1'b1;
                end else begin
                    Q1_DUMMY <= ~Q1_DUMMY;
                end
            end else begin
                if (XLXN_3 == 1) begin
                    Q1_DUMMY <= 1'b0;
                end
            end
        end
    end

    assign XLXN_8 = XLXN_9 | XLXN_10;
    assign XLXN_9 = Q0_DUMMY & Q3;
    assign XLXN_11 = ~Q0_DUMMY;
    assign XLXN_12 = ~Q3;
    assign XLXN_8 =  Q0_DUMMY & Q3 | Q2_DUMMY  & XLXN_11 & XLXN_12;


    always @(posedge CLK or posedge CLR) begin
