            Q2_DUMMY <= 1'b1;
        end else if (CE) begin
            Q2_DUMMY <= ~Q2_DUMMY;
        end
    end

    assign TC = ~(Q0_DUMMY ^ Q1_DUMMY ^ Q2_DUMMY ^ Q3) & (Q1_DUMMY & Q2_DUMMY & Q3);

    assign CEO = CE & TC;

