        if (!aresetn) begin
            // Resetting all signals
            s_axi_awready <= 0;
            s_axi_wready <= 0;
            s_axi_bresp <= 0;
            s_axi_bvalid <= 0;
            s_axi_arready <= 0;
            s_axi_rdata <= 0;
            s_axi_rresp <= 0;
            s_axi_rvalid <= 0;
            m_axi_awaddr <= 0;
