                s_axi_rvalid <= 1;
            end else if (s_axi_rvalid && s_axi_rready) begin
                s_axi_rvalid <= 0;
            end

            // Master AXI interface logic
            m_axi_awaddr <= {3{s_axi_awaddr}};
