            m_axi_bready <= {3{s_axi_bready}};

            m_axi_araddr <= {3{s_axi_araddr}};
            m_axi_arprot <= {3{s_axi_arprot}};
            m_axi_arvalid <= {3{s_axi_arvalid}};
            m_axi_rready <= {3{s_axi_rready}};
        end
    end
endmodule

