        s_axi_rdata <= m_axi_rdata;
        s_axi_rresp <= m_axi_rresp;
        s_axi_rlast <= 1;
        s_axi_rvalid <= 1;
        if (s_axi_rready) begin
          s_axi_rvalid <= 0;
          s_axi_rlast <= 0;
        end
