module rtlpp_03996(
    input            clk,
    input            rst,
    input            rx,
    output           tx, 
    input            transmit,
    input [7:0]      tx_byte,
    output reg       received,
    output reg [7:0] rx_byte,
    output           is_receiving,
    output           is_transmitting,
    output reg       recv_error,
