      RX_IDLE: begin
        if (!rx_ff) begin
          rx_clk_divider <= CLOCK_DIVIDE;
          rx_countdown <= 8;
          recv_state <= RX_CHECK_START;
        end
      end

      RX_CHECK_START: begin
        if (rx_countdown == 0) begin
          if (!rx_ff) begin
            rx_countdown <= 16;
            rx_bits_remaining <= 8;
            recv_state <= RX_READ_BITS;
          end else begin
            recv_state <= RX_ERROR;
          end
