        end
      end

      RX_CHECK_STOP: begin
        if (rx_countdown == 0) begin
          recv_state <= (rx_ff ? RX_RECEIVED : RX_ERROR);
        end
      end

      RX_DELAY_RESTART: begin
        if (rx_countdown != 0)
          recv_state <= RX_DELAY_RESTART;
        else
          recv_state <= RX_IDLE;
      end

      RX_ERROR: begin
        rx_countdown <= 32;
        recv_state <= RX_DELAY_RESTART;
      end

      RX_RECEIVED: begin
        recv_state <= RX_IDLE;
      end

      default: recv_state <= RX_IDLE;
    endcase

    case (tx_state)
      TX_IDLE: begin
        if (transmit) begin
          tx_data <= tx_byte;
          tx_clk_divider <= CLOCK_DIVIDE;
          tx_countdown <= 16;
          tx_out <= 0;
          tx_bits_remaining <= 8;
          tx_state <= TX_SENDING;
        end
      end

      TX_SENDING: begin
        if (tx_countdown == 0) begin
          if (tx_bits_remaining != 0) begin
            tx_bits_remaining <= tx_bits_remaining - 1;
            tx_out <= tx_data[0];
            tx_data <= {1'b0, tx_data[7:1]};
            tx_countdown <= 16;
          end else begin
            tx_out <= 1;
            tx_countdown <= 32;
            tx_state <= TX_DELAY_RESTART;
          end
        end
      end

      TX_DELAY_RESTART: begin
        if (tx_countdown != 0)
          tx_state <= TX_DELAY_RESTART;
        else
          tx_state <= TX_IDLE;
      end

      default: tx_state <= TX_IDLE;
    endcase
  end
end

