                if (transmit) begin
                    tx_data <= tx_byte;
                    tx_out <= 0;
                    tx_countdown <= 16;
                    tx_bits_remaining <= 8;
                    tx_state <= TX_SENDING;
                end
            end
            TX_SENDING: begin
                if (tx_countdown == 0) begin
                    if (tx_bits_remaining > 0) begin
                        tx_bits_remaining <= tx_bits_remaining - 1;
                        tx_out <= tx_data[0];
                        tx_data <= {1'b0, tx_data[7:1]};
                        tx_countdown <= 16;
                    end else begin
                        tx_out <= 1;
                        tx_countdown <= 32;
                        tx_state <= TX_DELAY_RESTART;
                    end
                end
            end
            TX_DELAY_RESTART: begin
                if (tx_countdown == 0)
                    tx_state <= TX_IDLE;
            end
            default: tx_state <= TX_IDLE;
        endcase
    end
end

endmodule

