files.autovcoder_139686.v:
module autovcoder_139686 (
    input clk,
    input rst,
    input [7:0] data_in,
    input valid_in,
    output reg [11:0] code_out,
    output reg valid_out
);
    reg [7:0] dictionary [0:4095]; // Dictionary for LZW
    reg [11:0] dict_size; // Current size of the dictionary
    reg [7:0] current_seq [0:255]; // Current sequence being processed
    reg [7:0] seq_length; // Length of the current sequence
    reg [11:0] last_code; // Last code outputted

    initial begin
        dict_size = 0;
        seq_length = 0;
        last_code = 0;
        valid_out = 0;
    end

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            dict_size <= 0;
            seq_length <= 0;
            last_code <= 0;
            valid_out <= 0;
        end else if (valid_in) begin
            if (seq_length == 0 || current_seq[seq_length - 1] == data_in) begin
                // Extend the current sequence
                current_seq[seq_length] = data_in;
                seq_length = seq_length + 1;
            end else begin
                // Output the code for the found sequence
                code_out = last_code; // Output the last code
                valid_out = 1;
                last_code = dict_size; // Assign new code for the current sequence

                // Add the new sequence to the dictionary
                dictionary[dict_size] = current_seq[0]; // Store the sequence in the dictionary
                dict_size = dict_size + 1;

                // Reset current sequence
                current_seq[0] = data_in;
                seq_length = 1;
            end
        end else begin
            valid_out = 0; // No valid output if input is not valid
        end
    end
endmodule

files.autovcoder_132991.v:
module autovcoder_132991(  
    input clk,  
    input reset,  
    input [15:0] angle,  
    output reg [15:0] sine,  
    output reg [15:0] cosine  
);  
    parameter N = 16;  
    reg [15:0] x, y;  
    reg [15:0] z;  
    reg [3:0] i;  
    reg [15:0] atan_table [0:N-1];  

    initial begin  
        // Initialize atan values for CORDIC  
        atan_table[0] = 16'h3C90; // atan(1) = 45 degrees  
        atan_table[1] = 16'h3B6E; // atan(0.5)  
        // ... more values for atan(1/2^i)  
        atan_table[2] = 16'h3A8C;  
        atan_table[3] = 16'h39F2;  
        atan_table[4] = 16'h39A4;  
        //... continue initializing up to atan_table[15]  
    end  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            x <= 16'h0001; // Initial x value (cos(0))  
            y <= 16'h0000; // Initial y value (sin(0))  
            z <= angle;  
            i <= 0;  
            sine <= 16'h0000;  
            cosine <= 16'h0000;  
        end else if (i < N) begin  
            if (z < 0) begin  
                // Perform CORDIC rotation  
                x <= x + (y >>> i);  
                y <= y - (x >>> i);  
                z <= z + atan_table[i];  
            end else begin  
                x <= x - (y >>> i);  
                y <= y + (x >>> i);  
                z <= z - atan_table[i];  
            end  
            i <= i + 1;  
        end else begin  
            sine <= y;  
            cosine <= x;  
        end  
    end  
endmodule

files.origen_083359.v:
module origen_083359 #(
    parameter WIDTH = 16
) (
    input wire clk,
    input wire rst,
    input wire drv_dir,
    input wire enable,
    input wire counter_en,
    input wire [2*WIDTH-1:0] drv_period,
    input wire [2*WIDTH-1:0] PULSE_NUMBER,
    output reg [2*WIDTH-1:0] drv_pulse
);

    reg pulse_invert;
    reg drv_step;
    reg [WIDTH-1:0] count_N;
    reg [WIDTH-1:0] drv_count;

    always @(posedge clk) begin
        if (rst || !enable) begin
            drv_count <= 0;
            count_N <= 0;
            pulse_invert <= 0;
            drv_step <= 0;
        end else begin
            // Counter logic
            if (drv_count >= drv_period[WIDTH-1:0] - 1) begin
                drv_count <= 0;
            end else begin
                drv_count <= drv_count + 1;
            end

            // Pulse generation
            if (drv_count >= 1 && drv_count <= (drv_period[WIDTH-1:0] >> 2)) begin
                drv_step <= 1;
            end else begin
                drv_step <= 0;
            end

            // Pulse counting
            if (counter_en && drv_count == 1) begin
                if (count_N >= PULSE_NUMBER[WIDTH-1:0] - 1) begin
                    count_N <= 0;
                end else begin
                    count_N <= count_N + 1;
                end
            end

            // Output generation
            drv_pulse <= {WIDTH{drv_step ^ pulse_invert}};
        end
    end

endmodule

files.origen_050866.v:
module origen_050866 (
    input wire CLOCK,
    input wire Reset,
    input wire [1:0] S,
    input wire [9:0] P,
    input wire [9:0] BeginCount,
    input wire [9:0] EndCount,
    output reg [9:0] Q,
    output reg TerminalCount
);

    reg [9:0] NextQ;

    always @(posedge CLOCK or posedge Reset) begin
        if (Reset)
            Q <= BeginCount;
        else
            Q <= NextQ;
    end

    always @(*) begin
        case (S)
            2'b00: begin // Hold
                NextQ = Q;
                TerminalCount = 1'b0;
            end
            2'b01: begin // Count Up
                if (Q == EndCount) begin
                    NextQ = 10'd0;
                    TerminalCount = 1'b1;
                end else begin
                    NextQ = Q + 1'b1;
                    TerminalCount = 1'b0;
                end
            end
            2'b10: begin // Count Down
                if (Q == BeginCount) begin
                    NextQ = EndCount;
                    TerminalCount = 1'b1;
                end else begin
                    NextQ = Q - 1'b1;
                    TerminalCount = 1'b0;
                end
            end
            2'b11: begin // Parallel Load
                NextQ = P;
                TerminalCount = 1'b0;
            end
        endcase
    end

endmodule

