module origen_112126 #(
    parameter DATA_WIDTH = 32,
    parameter RAM_DEPTH = 8,
    parameter BASE_ADDR = 0,
    parameter RAM_FILE = ""
) (
    input wire clk,
    input wire n_rst,

    // Read port
    input wire i_ram_rd_en,
    input wire [$clog2(RAM_DEPTH)-1:0] i_ram_rd_addr,
    output reg [DATA_WIDTH-1:0] o_ram_rd_data,

    // Write port
    input wire i_ram_wr_en,
    input wire [(DATA_WIDTH/8)-1:0] i_ram_wr_byte_en,
    input wire [$clog2(RAM_DEPTH)-1:0] i_ram_wr_addr,
    input wire [DATA_WIDTH-1:0] i_ram_wr_data
);

    localparam ADDR_WIDTH = $clog2(RAM_DEPTH);
    localparam NUM_BYTES = DATA_WIDTH / 8;

    reg [7:0] ram [RAM_DEPTH*NUM_BYTES-1:0];

    integer i;

    initial begin
        if (RAM_FILE != "") begin
            $readmemh(RAM_FILE, ram);
        end
    end

    // Asynchronous read
    always @(*) begin
        if (n_rst && i_ram_rd_en) begin
            for (i = 0; i < NUM_BYTES; i = i + 1) begin
                o_ram_rd_data[i*8 +: 8] = ram[i_ram_rd_addr * NUM_BYTES + i];
            end
        end else begin
            o_ram_rd_data = {DATA_WIDTH{1'b0}};
        end
    end

    // Synchronous write
    always @(posedge clk) begin
        if (n_rst && i_ram_wr_en) begin
            for (i = 0; i < NUM_BYTES; i = i + 1) begin
                if (i_ram_wr_byte_en[i]) begin
                    ram[i_ram_wr_addr * NUM_BYTES + i] <= i_ram_wr_data[i*8 +: 8];
                end
            end
        end
    end

endmodule

files.origen_100383.v:
module origen_100383(
    input wire clk,
    input wire reset,
    input wire resetRound,
    input wire L, U, D, R,
    input wire NL, NU, ND, NR,
    output reg lightOn
);

    // State definition
    localparam OFF = 1'b0;
    localparam ON = 1'b1;

    reg state, next_state;

    // State transition logic
    always @(*) begin
        case (state)
            OFF: begin
                if ((L && NR && !U && !D && !R) ||
                    (R && NL && !U && !D && !L) ||
                    (U && ND && !L && !D && !R) ||
                    (D && NU && !L && !U && !R))
                    next_state = ON;
                else
                    next_state = OFF;
            end
            ON: begin
                if ((L && !U && !D && !R) ||
                    (R && !U && !D && !L) ||
                    (U && !L && !D && !R) ||
                    (D && !L && !U && !R))
                    next_state = OFF;
                else
                    next_state = ON;
            end
            default: next_state = OFF;
        endcase
    end

    // State register
    always @(posedge clk or posedge reset or posedge resetRound) begin
        if (reset || resetRound)
            state <= OFF;
        else
            state <= next_state;
    end

    // Output logic
    always @(*) begin
        lightOn = (state == ON);
    end

endmodule

files.origen_041274.v:
module origen_041274 (
    input wire rst_n,
    input wire clk,
    input wire clr,
    input wire en_sw,
    input wire en_tb,
    input wire [11:0] init_mvec,
    output reg [11:0] addr_sw,
    output reg [7:0] addr_tb
);

reg en_sw_pre;
reg [4:0] cnt_h, cnt_w;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        addr_sw <= #1 12'h000;
        addr_tb <= #1 8'h00;
        en_sw_pre <= #1 1'b0;
        cnt_h <= #1 5'h00;
        cnt_w <= #1 5'h00;
    end else if (clr) begin
        addr_sw <= #1 12'h000;
        addr_tb <= #1 8'h00;
        en_sw_pre <= #1 1'b0;
        cnt_h <= #1 5'h00;
        cnt_w <= #1 5'h00;
    end else begin
        en_sw_pre <= #1 en_sw;

        if (en_sw && !en_sw_pre) begin
            addr_sw <= #1 init_mvec;
            cnt_h <= #1 5'h00;
            cnt_w <= #1 5'h00;
        end else if (en_sw) begin
            if (cnt_h < 5'd17) begin
                addr_sw[5:0] <= #1 addr_sw[5:0] + 1'b1;
                cnt_h <= #1 cnt_h + 1'b1;
            end else begin
                addr_sw[11:6] <= #1 addr_sw[11:6] + 1'b1;
                addr_sw[5:0] <= #1 init_mvec[5:0] - 6'd17;
                cnt_h <= #1 5'h00;
                cnt_w <= #1 cnt_w + 1'b1;
            end
        end

        if (en_tb) begin
            addr_tb <= #1 addr_tb + 1'b1;
        end
    end
end

endmodule

files.origen_068464.v:
module origen_068464 (
    input wire clock,
    input wire reset,
    input wire is_ringing,
    input wire is_playing,
    output reg music
);

    // State encoding
    localparam [1:0] Q0_Init = 2'b00,
                     Q1_MusicOff = 2'b01,
                     Q2_MusicResume = 2'b10;

    reg [1:0] current_state, next_state;

    // State register
    always @(posedge clock or posedge reset) begin
        if (reset)
            current_state <= Q0_Init;
        else
            current_state <= next_state;
    end

    // Next state logic
    always @(*) begin
        case (current_state)
            Q0_Init: begin
                if (is_playing && is_ringing)
                    next_state = Q1_MusicOff;
                else
                    next_state = Q0_Init;
            end
            Q1_MusicOff: begin
                if (!is_ringing)
                    next_state = Q2_MusicResume;
                else
                    next_state = Q1_MusicOff;
            end
            Q2_MusicResume: next_state = Q0_Init;
            default: next_state = Q0_Init;
        endcase
    end

    // Output logic
    always @(*) begin
        case (current_state)
            Q0_Init: music = 1'b1;
            Q1_MusicOff: music = 1'b0;
            Q2_MusicResume: music = 1'b1;
            default: music = 1'b1;
        endcase
