    reg [1:0] state, next_state;
    reg signed [25:0] temp_num, temp_den;
    reg num_sign, den_sign;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= S0;
            result <= 16'b0;
            done <= 1'b0;
        end else begin
            state <= next_state;
            case (state)
                S0: begin
                    if (start) begin
                        num_sign <= num[15];
                        den_sign <= den[15];
                        temp_num <= num_sign ? (~num + 1'b1) : num;
                        temp_den <= den_sign ? (~den + 1'b1) : den;
