                S2: begin
                    result <= ~(temp_num[25:10] / temp_den[20:5]) + 1'b1;
                    done <= 1'b1;
                end
            endcase
        end
    end

    always @(*) begin
        case (state)
            S0: next_state = start ? (num_sign ^ den_sign ? S2 : S1) : S0;
            S1, S2: next_state = start ? state : S0;
            default: next_state = S0;
        endcase
    end

