reg [6:0] a_to_g_reg;
always @(*) begin
    case (digit)
        4'd0: a_to_g_reg = 7'b1000000;
        4'd1: a_to_g_reg = 7'b1111001;
        4'd2: a_to_g_reg = 7'b0100100;
        4'd3: a_to_g_reg = 7'b0110000;
