module origen_011921 (
    input wire clk, rst, set_mode,
    input wire r_end, y_end, g_end,
    input wire c_s,
    output reg [2:0] A, B,
    output reg fsm_r, fsm_y, fsm_g
);

    // State encoding
    localparam [2:0] AR_BR  = 3'b000,
                     AR_BY  = 3'b001,
                     AR_BG  = 3'b010,
                     AR_BY1 = 3'b011,
                     AY_BR  = 3'b100,
                     AG_BR  = 3'b101,
                     AY_BR1 = 3'b110;

    reg [2:0] current_state, next_state;

    // State register
    always @(posedge clk or posedge rst or posedge set_mode) begin
        if (rst || set_mode)
            current_state <= AR_BR;
        else
            current_state <= next_state;
    end

    // Next state logic
    always @(*) begin
        case (current_state)
            AR_BR:  next_state = r_end ? AR_BY : AR_BR;
            AR_BY:  next_state = y_end ? AR_BG : AR_BY;
            AR_BG:  next_state = (g_end || c_s) ? AR_BY1 : AR_BG;
            AR_BY1: next_state = y_end ? AY_BR : AR_BY1;
            AY_BR:  next_state = y_end ? AG_BR : AY_BR;
            AG_BR:  next_state = (g_end || c_s) ? AY_BR1 : AG_BR;
            AY_BR1: next_state = y_end ? AR_BR : AY_BR1;
            default: next_state = AR_BR;
        endcase
    end

    // Output logic
    always @(*) begin
        case (current_state)
            AR_BR:  begin A = 3'b100; B = 3'b100; fsm_r = 1; fsm_y = 0; fsm_g = 0; end
            AR_BY:  begin A = 3'b100; B = 3'b010; fsm_r = 1; fsm_y = 1; fsm_g = 0; end
            AR_BG:  begin A = 3'b100; B = 3'b001; fsm_r = 1; fsm_y = 0; fsm_g = 1; end
            AR_BY1: begin A = 3'b100; B = 3'b010; fsm_r = 1; fsm_y = 1; fsm_g = 0; end
            AY_BR:  begin A = 3'b010; B = 3'b100; fsm_r = 1; fsm_y = 1; fsm_g = 0; end
            AG_BR:  begin A = 3'b001; B = 3'b100; fsm_r = 1; fsm_y = 0; fsm_g = 1; end
            AY_BR1: begin A = 3'b010; B = 3'b100; fsm_r = 1; fsm_y = 1; fsm_g = 0; end
            default: begin A = 3'b100; B = 3'b100; fsm_r = 1; fsm_y = 0; fsm_g = 0; end
        endcase
    end

endmodule

