);

    reg vga_clk;
    reg [11:0] data_reg;
    wire video_out;
    wire rdn;
    reg [9:0] h_count;
    reg [9:0] v_count;

    always @(posedge clk or negedge clrn) begin
        if (!clrn) begin
            vga_clk <= 1'b0;
        end else begin
            vga_clk <= ~vga_clk;
        end
    end

    always @(posedge vga_clk or negedge clrn) begin
        if (!clrn) begin
            h_count <= 10'd0;
            v_count <= 10'd0;
            data_reg <= 12'd0;
        end else begin
            h_count <= (h_count == 10'd799) ? 10'd0 : h_count + 1'b1;
            if (h_count == 10'd799) begin
                v_count <= (v_count == 10'd524) ? 10'd0 : v_count + 1'b1;
            end
            data_reg <= d_in;
        end
    end

    assign video_out = ~rdn;
