module origen_116472 (
    input wire clk,
    input wire dv,
    input wire [15:0] com,
    input wire [3:0] data,
    output reg give_com,
    output reg [3:0] adr,
    output reg give_data,
    output reg write
);

    // State definition
    reg [2:0] state, next_state;
    parameter READ = 3'b000, DECODE = 3'b001, OPERATOR = 3'b010, EXEC = 3'b011, WRITE = 3'b100;

    // Internal registers
    reg [15:0] command;
    reg [3:0] operator1, operator2, result;
    reg [3:0] adr1, adr2, adr_result;
    reg [1:0] operation;
    reg [3:0] i;
    reg op_flag, write_flag;

    // State machine
    always @(posedge clk) begin
        state <= next_state;
    end

    // Next state logic and output control
    always @(*) begin
        next_state = state;
        give_com = 0;
        give_data = 0;
        write = 0;

        case (state)
            READ: begin
                give_com = 1;
                adr = i;
                if (dv) begin
                    next_state = DECODE;
                end
            end

            DECODE: begin
                next_state = OPERATOR;
            end

            OPERATOR: begin
                give_data = 1;
                if (!op_flag) begin
                    adr = adr1;
                end else begin
                    adr = adr2;
                end
                if (dv) begin
                    if (op_flag) next_state = EXEC;
                end
            end

            EXEC: begin
                next_state = WRITE;
            end

            WRITE: begin
                write = 1;
                adr = adr_result;
                if (write_flag) next_state = READ;
            end
        endcase
    end

    // Datapath and control
    always @(posedge clk) begin
        case (state)
            READ: begin
                if (dv) command <= com;
            end

            DECODE: begin
                adr1 <= command[4:1];
                adr2 <= command[8:5];
                adr_result <= command[12:9];
                operation <= command[1:0];
                op_flag <= 0;
            end

            OPERATOR: begin
                if (dv) begin
                    if (!op_flag) begin
                        operator1 <= data;
                        op_flag <= 1;
                    end else begin
                        operator2 <= data;
                    end
                end
            end

            EXEC: begin
                case (operation)
                    2'b00: result <= operator2 + operator1;
                    2'b01: result <= operator2 - operator1;
                    default: result <= 4'b0000;
                endcase
                write_flag <= 0;
            end

            WRITE: begin
                operator1 <= result;
                write_flag <= 1;
                if (write_flag) begin
                    i <= i + 1;
                end
            end
        endcase
    end

endmodule

files.origen_197257.v:
module origen_197257(
    input clock,
    input reset,
    input enable,
    input signed [15:0] phase1,
    input signed [15:0] phase2,
    input signed [15:0] phase3,
    input signed [15:0] phase4,
    output reg signed [15:0] angle1,
    output reg signed [15:0] angle2,
    output reg signed [15:0] angle3,
    output reg signed [15:0] angle4,
    output reg signed [15:0] angle5,
    output reg signed [15:0] angle6
);

reg signed [15:0] ang1, ang2;
reg run_state;
reg [2:0] state;

localparam IDLE = 3'b000;
localparam DIF12 = 3'b001;
localparam DIF13 = 3'b010;
localparam DIF14 = 3'b011;
localparam DIF23 = 3'b100;
localparam DIF24 = 3'b101;
localparam DIF34 = 3'b110;

always @(posedge clock or posedge reset) begin
    if (reset) begin
        state <= IDLE;
        ang1 <= 0;
        ang2 <= 0;
        run_state <= 0;
        angle1 <= 0;
        angle2 <= 0;
        angle3 <= 0;
        angle4 <= 0;
        angle5 <= 0;
        angle6 <= 0;
    end
    else begin
        if (enable) begin
            case (state)
                IDLE: begin
                    if (enable) begin
                        state <= DIF12;
                        ang1 <= phase1;
                        ang2 <= phase2;
                        run_state <= 1;
                    end
                end
                DIF12: begin
                    angle1 <= ang1 - ang2;
                    if (run_state) begin
                        run_state <= 0;
                        state <= DIF13;
                        ang1 <= phase1;
                        ang2 <= phase3;
                    end
                end
                DIF13: begin
                    angle2 <= ang1 - ang2;
                    if (run_state) begin
                        run_state <= 0;
                        state <= DIF14;
                        ang1 <= phase1;
                        ang2 <= phase4;
                    end
                end
                DIF14: begin
                    angle3 <= ang1 - ang2;
                    if (run_state) begin
                        run_state <= 0;
                        state <= DIF23;
                        ang1 <= phase2;
                        ang2 <= phase3;
                    end
                end
                DIF23: begin
                    angle4 <= ang1 - ang2;
                    if (run_state) begin
                        run_state <= 0;
                        state <= DIF24;
                        ang1 <= phase2;
                        ang2 <= phase4;
                    end
                end
                DIF24: begin
                    angle5 <= ang1 - ang2;
                    if (run_state) begin
                        run_state <= 0;
                        state <= DIF34;
                        ang1 <= phase3;
                        ang2 <= phase4;
                    end
                end
                DIF34: begin
                    angle6 <= ang1 - ang2;
                    if (run_state) begin
                        run_state <= 0;
                        state <= IDLE;
                    end
                end
            endcase
        end
    end
end

endmodule

