        .load(load),
        .go(go),
        .controlX(controlX),
        .controlY(controlY),
        .controlC(controlC),
        .writeEn(writeEn),
        .enable_x(enable_x)
    );

    datapath D0(
        .clock(clock),
        .resetn(resetn),
        .controlX(controlX),
        .controlY(controlY),
        .controlC(controlC),
        .enable_x(enable_x),
        .colour_in(colour_in),
        .location(location),
        .x_out(x_out),
        .y_out(y_out),
        .colour_out(colour_out)
    );

